const POKEMON = [
  'メガライチュウX', 'メガライチュウY', 'ラフレシア', 'ハリーセン', 'ジュカイン', 'メガジュカイン',
  'バシャーモ', 'メガバシャーモ', 'ラグラージ', 'メガラグラージ', 'クチート', 'メガクチート',
  'メタグロス', 'メガメタグロス', 'ムクホーク', 'メガムクホーク', 'ムシャーナ', 'ペンドラー',
  'メガペンドラー', 'ズルズキン', 'メガズルズキン', 'シビルドン', 'メガシビルドン', 'カエンジシ',
  'メガカエンジシ', 'カラマネロ', 'メガカラマネロ', 'ガメノデス', 'メガガメノデス', 'ドラミドロ',
  'メガドラミドロ', 'オーロンゲ', 'タイレーツ', 'メガタイレーツ', 'ハリーマン', 'ハカドッグ',
  'コノヨザル', 'サーフゴー'
];

// メガポケモンの基本ポケモンマップ(技習得は同じ)
const MEGA_TO_BASE = {
  'メガライチュウX': 'ライチュウ', 'メガライチュウY': 'ライチュウ',
  'メガジュカイン': 'ジュカイン', 'メガバシャーモ': 'バシャーモ',
  'メガラグラージ': 'ラグラージ', 'メガクチート': 'クチート',
  'メガメタグロス': 'メタグロス', 'メガムクホーク': 'ムクホーク',
  'メガペンドラー': 'ペンドラー', 'メガズルズキン': 'ズルズキン',
  'メガシビルドン': 'シビルドン', 'メガカエンジシ': 'カエンジシ',
  'メガカラマネロ': 'カラマネロ', 'メガガメノデス': 'ガメノデス',
  'メガドラミドロ': 'ドラミドロ', 'メガタイレーツ': 'タイレーツ',
};

const SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['name', 'learned_techs', 'sources'],
  properties: {
    name: { type: 'string' },
    learned_techs: { type: 'array', items: { type: 'string' }, description: 'WAZA_MAPに存在する技のうち、このポケモンが覚える技の日本語名リスト' },
    sources: { type: 'array', items: { type: 'string' }, description: '参照URL2つ以上' }
  }
};

phase('Research');
const TECH_LIST = allTechs.join('、');
const results = await parallel(POKEMON.map(pname => () => {
  const base = MEGA_TO_BASE[pname] || pname;
  const note = MEGA_TO_BASE[pname] ? `(メガシンカ前=${base}と同じ技を覚える。メガ専用技なし)` : '';
  return agent(
    'あなたはポケモン技習得データ調査担当。WebSearch+WebFetchで対象ポケモンが覚える技を調べて、'
    + 'pchamdb の WAZA_MAP に登録されている490技の中から、そのポケモンが覚える技だけを抽出する。\n\n'
    + '対象: ' + pname + ' ' + note
    + '\n\n調査手順:\n'
    + '1. 「' + base + ' 覚える技」「' + base + ' 技マシン」「' + base + ' レベルアップ技」でWebSearch\n'
    + '2. GameWith / ポケモン徹底攻略 / Bulbapedia / Game8 のうち最低2サイトをWebFetch\n'
    + '3. レベルアップ技・タマゴ技・わざマシン・教え技を全部リストアップ\n'
    + '4. 抽出した技名を、以下の490技マスターと照合\n'
    + '5. マスターに存在する技だけ learned_techs に含める\n\n'
    + 'WAZA_MAP の490技マスター(これに含まれる技だけ返すこと):\n'
    + TECH_LIST
    + '\n\n注意:\n'
    + '- 技名は完全一致(ひらがな・カタカナ・記号も含めて)\n'
    + '- マスターにない技は除外(無視)\n'
    + '- メガポケモンは基本ポケモンと同じ技を覚える\n'
    + '- sources に必ず2サイト以上のURL記載',
    { label: pname, phase: 'Research', schema: SCHEMA, model: 'sonnet' }
  );
}));

const ok = results.filter(Boolean);
log('調査完了: ' + ok.length + '/' + POKEMON.length);

// 統計
let totalLearned = 0;
for (const r of ok) totalLearned += r.learned_techs.length;
log('総技数: ' + totalLearned + ' (平均 ' + Math.round(totalLearned / ok.length) + '技/ポケモン)');

return { researched: ok.length, total: POKEMON.length, items: ok };
